import { useState, useEffect } from "react";
import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

const countryCityMap = {
  India: ["Delhi", "Mumbai", "Pune", "Bangalore", "Chennai"],
  UAE: ["Dubai", "Abu Dhabi", "Sharjah"],
  USA: ["New York", "California", "Texas"],
};

export default function AddPatient() {
  const [dob, setDob] = useState("");
  const [age, setAge] = useState("");
  const [country, setCountry] = useState("");
  const [cityList, setCityList] = useState([]);

  useEffect(() => {
    if (dob) {
      const birth = new Date(dob);
      const today = new Date();
      let calculatedAge = today.getFullYear() - birth.getFullYear();
      const m = today.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
        calculatedAge--;
      }
      setAge(calculatedAge);
    }
  }, [dob]);

  const handleCountryChange = (e) => {
    const value = e.target.value;
    setCountry(value);
    setCityList(countryCityMap[value] || []);
  };

  return (
    <AdminLayout>
      <div className="patient-page">

        <div className="patient-header">
          <h2>Patient Registration</h2>
          <p>HL7 v2.5 • ADT A04</p>
        </div>

        <div className="patient-card">

          {/* Patient Info */}
          <section>
            <h3>Patient Information</h3>

            <div className="top-grid">
              <div className="photo-box">
                <div className="avatar"></div>
                <label className="upload">Upload Photo</label>
                <input type="file" hidden />
              </div>

              <div className="grid">
                <div>
                  <label>MRN</label>
                  <input placeholder="MRN123" />
                </div>
                <div>
                  <label>First Name</label>
                  <input placeholder="John" />
                </div>
                <div>
                  <label>Last Name</label>
                  <input placeholder="Doe" />
                </div>
                <div>
                  <label>Display Name</label>
                  <input placeholder="John Doe" />
                </div>
                <div>
                  <label>Date of Birth</label>
                  <input type="date" onChange={(e) => setDob(e.target.value)} />
                </div>
                <div>
                  <label>Age</label>
                  <input value={age} disabled />
                </div>
                <div>
                  <label>Gender</label>
                  <select>
                    <option>Male</option>
                    <option>Female</option>
                  </select>
                </div>
                <div>
                  <label>Marital Status</label>
                  <select>
                    <option>Single</option>
                    <option>Married</option>
                  </select>
                </div>
              </div>
            </div>
          </section>

          {/* Contact */}
          <section>
            <h3>Contact Details</h3>

            <div className="grid">
              <div>
                <label>Address</label>
                <input placeholder="123 Main St" />
              </div>
              <div>
                <label>Country</label>
                <select onChange={handleCountryChange}>
                  <option>Select Country</option>
                  {Object.keys(countryCityMap).map((c) => (
                    <option key={c}>{c}</option>
                  ))}
                </select>
              </div>
              <div>
                <label>City</label>
                <select>
                  {cityList.map((c) => (
                    <option key={c}>{c}</option>
                  ))}
                </select>
              </div>
              <div>
                <label>Mobile Number</label>
                <input placeholder="+91 9876543210" />
              </div>
              <div>
                <label>National ID Number</label>
                <input placeholder="XXXX XXXX XXXX" />
              </div>
            </div>
          </section>

          {/* Patient ID */}
          <section>
            <h3>Patient Identification</h3>

            <div className="grid">
              <div>
                <label>ID Type</label>
                <select>
                  <option>Aadhaar Card</option>
                  <option>Passport</option>
                  <option>PAN Card</option>
                  <option>Voter ID</option>
                  <option>Driving License</option>
                </select>
              </div>
              <div>
                <label>ID Number</label>
                <input />
              </div>
              <div>
                <label>Expiry Date</label>
                <input type="date" />
              </div>
              <div className="scan-box">
                <label>Scan ID</label>
                <button>Scan / Upload</button>
              </div>
            </div>
          </section>

          {/* Emergency */}
          <section>
            <h3>Emergency Contact</h3>

            <div className="grid">
              <div>
                <label>First Name</label>
                <input />
              </div>
              <div>
                <label>Last Name</label>
                <input />
              </div>
              <div>
                <label>Relationship</label>
                <select>
                  <option>Father</option>
                  <option>Mother</option>
                  <option>Brother</option>
                  <option>Sister</option>
                  <option>Husband</option>
                  <option>Cousin</option>
                  <option>Other</option>
                </select>
              </div>
              <div>
                <label>Mobile Number</label>
                <input />
              </div>
              <div>
                <label>ID Type</label>
                <select>
                  <option>Aadhaar</option>
                  <option>Passport</option>
                  <option>PAN</option>
                </select>
              </div>
              <div>
                <label>ID Number</label>
                <input />
              </div>
              <div>
                <label>Expiry Date</label>
                <input type="date" />
              </div>
            </div>
          </section>

          <div className="actions">
            <button className="submit">Register Patient</button>
          </div>

        </div>
      </div>
    </AdminLayout>
  );
}
